/** Auto-generated from assets/brand/missions/*.png — Granite `{ uri }`. */
export const MISSION_IMAGE_URI = {
    'tumbler': 'data:image/png;base64,',
    'bag': 'data:image/png;base64,',
    'reusable': 'data:image/png;base64,',
    'recycle': 'data:image/png;base64,',
    'transit': 'data:image/png;base64,',
    'pickup-not-delivery': 'data:image/png;base64,',
    'almang-visit': 'data:image/png;base64,',
    'refill-station': 'data:image/png;base64,',
    'plogging': 'data:image/png;base64,',
    'coop-photo-start': 'data:image/png;base64,',
    'coop-receipt': 'data:image/png;base64,',
    'coop-week-attendance': 'data:image/png;base64,',
} as const;

export type MissionImageUriKey = keyof typeof MISSION_IMAGE_URI;

export function missionUriSource(key: MissionImageUriKey): { uri: string } {
    return { uri: MISSION_IMAGE_URI[key] };
}
